var processPacketCommands = function(commands) {
    const buffer = [];    // 缓冲区 FIFO
    const sendQ = [];     // 发送区 FIFO
    const inBuffer = new Set();
    const ans = [];

    const flush = () => {
        // 发送区为空时，将缓冲区全部按 FIFO 移入发送区
        while (buffer.length) {
            const x = buffer.shift();
            inBuffer.delete(x);
            sendQ.push(x);
        }
    };

    for (const cmd of commands) {
        if (cmd.startsWith('RECEIVE')) {
            const x = parseInt(cmd.split(' ')[1], 10);
            // 仅检查缓冲区是否已有同编号
            if (inBuffer.has(x)) {
                ans.push(-1);
            } else {
                buffer.push(x);
                inBuffer.add(x);
                ans.push(x);
            }
        } else if (cmd === 'SEND') {
            if (sendQ.length > 0) {
                ans.push(sendQ.shift());
            } else if (buffer.length > 0) {
                flush();
                ans.push(sendQ.shift());
            } else {
                ans.push(0);
            }
        } else if (cmd === 'QUERY') {
            if (sendQ.length > 0) {
                ans.push(sendQ[0]);  // 只查队首，不弹出
            } else if (buffer.length > 0) {
                flush();
                ans.push(sendQ[0]);
            } else {
                ans.push(0);
            }
        }
    }
    return ans;
};
