#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

int* processPacketCommands(char** commands, int commandsSize, int* returnSize) {
    int* ans = (int*)malloc(commandsSize * sizeof(int));
    // 缓冲区与发送区（FIFO 队列），n ≤ 100
    int buffer[105], bufH = 0, bufT = 0;
    int sendQ[105], sqH = 0, sqT = 0;
    // 仅记录缓冲区中已有的编号（x ≤ 1000），O(1) 判重
    bool inBuf[1005] = {false};

    for (int i = 0; i < commandsSize; i++) {
        if (strncmp(commands[i], "RECEIVE", 7) == 0) {
            int x = atoi(commands[i] + 8);  // 跳过 "RECEIVE "
            if (inBuf[x]) {
                // 缓冲区已有同编号，接收失败
                ans[i] = -1;
            } else {
                buffer[bufT++] = x;
                inBuf[x] = true;
                ans[i] = x;
            }
        } else if (strcmp(commands[i], "SEND") == 0) {
            if (sqH < sqT) {
                ans[i] = sendQ[sqH++];
            } else if (bufH < bufT) {
                // 发送区为空，将缓冲区全部移入发送区
                while (bufH < bufT) {
                    int x = buffer[bufH++];
                    inBuf[x] = false;
                    sendQ[sqT++] = x;
                }
                ans[i] = sendQ[sqH++];
            } else {
                ans[i] = 0;
            }
        } else if (strcmp(commands[i], "QUERY") == 0) {
            if (sqH < sqT) {
                ans[i] = sendQ[sqH];  // 只查队首，不弹出
            } else if (bufH < bufT) {
                while (bufH < bufT) {
                    int x = buffer[bufH++];
                    inBuf[x] = false;
                    sendQ[sqT++] = x;
                }
                ans[i] = sendQ[sqH];
            } else {
                ans[i] = 0;
            }
        }
    }
    *returnSize = commandsSize;
    return ans;
}
